  `last_approval_time` datetime NULL DEFAULT NULL COMMENT '鏈?悗涓??瀹℃壒閫氳繃鏃堕棿',
  PRIMARY KEY (`contract_id`) USING BTREE,
  INDEX `idx_customer_id`(`customer_id` ASC) USING BTREE,
  INDEX `idx_order_id`(`order_id` ASC) USING BTREE,
  INDEX `idx_contract_owner`(`belong_user_id` ASC) USING BTREE,
  INDEX `idx_contract_dept`(`belong_dept_id` ASC) USING BTREE
