DROP TABLE IF EXISTS `crm_customer_dispute`;
CREATE TABLE `crm_customer_dispute`  (
  `dispute_id` bigint NOT NULL AUTO_INCREMENT COMMENT '浜夎?ID',
  `customer_id` bigint NOT NULL COMMENT '瀹㈡埛ID',
  `initiator_user_id` bigint NOT NULL COMMENT '鍙戣捣浜',
  `target_user_id` bigint NULL DEFAULT NULL COMMENT '褰撳墠璐熻矗浜',
  `reason` varchar(500) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT NULL COMMENT '浜夎?鍘熷洜',
  `status` char(1) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT '0' COMMENT '0=寰呭?鐞?1=缁忕悊宸插?鐞?2=瓒呯?宸蹭徊瑁?3=宸插叧闂',
  `result` char(1) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT NULL COMMENT 'A=褰掑彂璧蜂汉 B=褰掑師璐熻矗浜',
  `handler_id` bigint NULL DEFAULT NULL COMMENT '澶勭悊浜篒D',
  `handle_time` datetime NULL DEFAULT NULL COMMENT '澶勭悊鏃堕棿',
  `remark` varchar(500) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT NULL COMMENT '澶勭悊澶囨敞',
  `create_by` varchar(64) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT '' COMMENT '鍒涘缓浜',
  `create_time` datetime NULL DEFAULT NULL COMMENT '鍒涘缓鏃堕棿',
  `update_by` varchar(64) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT '' COMMENT '鏇存柊浜',
  `update_time` datetime NULL DEFAULT NULL COMMENT '鏇存柊鏃堕棿',
  PRIMARY KEY (`dispute_id`) USING BTREE,
  INDEX `idx_customer_id`(`customer_id` ASC) USING BTREE,
  INDEX `idx_status`(`status` ASC) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 2 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_0900_ai_ci COMMENT = '瀹㈡埛鎾炲崟浜夎?' ROW_FORMAT = Dynamic;

