  INDEX `idx_payment_dept`(`belong_dept_id` ASC) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 74 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_0900_ai_ci COMMENT = '回款计划表' ROW_FORMAT = Dynamic;

