-- ----------------------------
-- Table structure for crm_pipeline
-- ----------------------------
DROP TABLE IF EXISTS `crm_pipeline`;
CREATE TABLE `crm_pipeline`  (
  `pipeline_id` bigint NOT NULL AUTO_INCREMENT COMMENT '漏斗ID',
  `customer_id` bigint NULL DEFAULT NULL COMMENT '客户ID',
  `order_id` bigint NULL DEFAULT NULL COMMENT '关联订单ID',
  `stage` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NOT NULL COMMENT '??',
  `amount` decimal(12, 2) NULL DEFAULT 0.00 COMMENT '预计金额',
  `probability` int NULL DEFAULT 0 COMMENT '成交概率（%）',
  `expected_close_date` datetime NULL DEFAULT NULL COMMENT '预计成交日期',
  `remark` varchar(500) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT NULL COMMENT '备注',
  `del_flag` char(1) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT '0' COMMENT '删除标志',
  `create_by` varchar(64) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT '' COMMENT '创建者',
  `create_time` datetime NULL DEFAULT NULL COMMENT '创建时间',
  `update_by` varchar(64) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT '' COMMENT '更新者',
  `update_time` datetime NULL DEFAULT NULL COMMENT '更新时间',
  `score` int NULL DEFAULT NULL COMMENT 'AI 鍟嗘満璇勫垎(0-100)',
  `score_reason` varchar(500) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT NULL COMMENT '璇勫垎鐞嗙敱',
  `score_time` datetime NULL DEFAULT NULL COMMENT '璇勫垎鏃堕棿',
  PRIMARY KEY (`pipeline_id`) USING BTREE,
  INDEX `idx_customer_id`(`customer_id` ASC) USING BTREE,
  INDEX `idx_stage`(`stage` ASC) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 77 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_0900_ai_ci COMMENT = '销售漏斗表' ROW_FORMAT = Dynamic;

