-- Table structure for sys_ai_log
-- ----------------------------
DROP TABLE IF EXISTS `sys_ai_log`;
CREATE TABLE `sys_ai_log`  (
  `id` bigint NOT NULL AUTO_INCREMENT,
  `user_id` bigint NOT NULL COMMENT '鐢ㄦ埛ID',
  `scene` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NOT NULL COMMENT '鍦烘櫙',
  `request_body` text CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL COMMENT '璇锋眰鍐呭?',
  `response_body` text CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL COMMENT '鍝嶅簲鍐呭?',
  `prompt_tokens` int NULL DEFAULT 0 COMMENT '杈撳叆token鏁',
  `completion_tokens` int NULL DEFAULT 0 COMMENT '杈撳嚭token鏁',
  `total_tokens` int NULL DEFAULT 0 COMMENT '鎬籺oken鏁',
  `duration_ms` int NULL DEFAULT 0 COMMENT '鑰楁椂ms',
  `status` char(1) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT '0' COMMENT '0鎴愬姛 1澶辫触',
  `error_msg` varchar(500) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT NULL COMMENT '閿欒?淇℃伅',
  `create_time` datetime NULL DEFAULT NULL COMMENT '璋冪敤鏃堕棿',
  PRIMARY KEY (`id`) USING BTREE,
  INDEX `idx_user`(`user_id` ASC) USING BTREE,
  INDEX `idx_scene`(`scene` ASC) USING BTREE,
  INDEX `idx_time`(`create_time` ASC) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 8 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_0900_ai_ci COMMENT = 'AI 璋冪敤鏃ュ織' ROW_FORMAT = Dynamic;

