INSERT INTO `sys_oper_log` VALUES (100, '创建表', 0, 'com.ruoyi.generator.controller.GenController.createTableSave()', 'POST', 1, 'admin', '研发部门', '/tool/gen/createTable', '127.0.0.1', '内网IP', '{\"sql\":\"-- 图书表\\nCREATE TABLE `book` (\\n  `book_id`          bigint(20) NOT NULL AUTO_INCREMENT COMMENT \'图书编号\',\\n  `book_name`        varchar(100) NOT NULL COMMENT \'书名\',\\n  `author`           varchar(50)  DEFAULT NULL COMMENT \'作者\',\\n  `isbn`             varchar(20)  DEFAULT NULL COMMENT \'ISBN\',\\n  `publish_date`     date         DEFAULT NULL COMMENT \'出版日期\',\\n  `price`            decimal(10,2) DEFAULT NULL COMMENT \'价格\',\\n  `stock`            int(11) DEFAULT \'0\' COMMENT \'库存\',\\n  `status`           char(1) DEFAULT \'0\' COMMENT \'状态（0正常 1停用）\',\\n  `create_by`        varchar(64)  DEFAULT NULL COMMENT \'创建者\',\\n  `create_time`      datetime     DEFAULT NULL COMMENT \'创建时间\',\\n  `update_by`        varchar(64)  DEFAULT NULL COMMENT \'更新者\',\\n  `update_time`      datetime     DEFAULT NULL COMMENT \'更新时间\',\\n  `remark`           varchar(500) DEFAULT NULL COMMENT \'备注\',\\n  PRIMARY KEY (`book_id`)\\n) ENGINE=InnoDB AUTO_INCREMENT=1 DEFAULT CHARSET=utf8mb4 COMMENT=\'图书表\';\\n\\n-- 初始化两条数据\\nINSERT INTO book VALUES (1,\'SpringBoot实战\',\'Craig Walls\',\'9787115470209\',\'2018-01-01\',89.00,100,\'0\',\'admin\',now(),\'admin\',now(),\'\');\\nINSERT INTO book VALUES (2,\'Vue.js入门\',\'尤雨溪\',\'9787121353049\',\'2019-05-01\',79.00,50,\'0\',\'admin\',now(),\'admin\',now(),\'\');\"}', '{\"msg\":\"创建表结构异常\",\"code\":500}', 0, NULL, '2025-11-18 18:12:08', 11);
INSERT INTO `sys_oper_log` VALUES (101, '创建表', 0, 'com.ruoyi.generator.controller.GenController.createTableSave()', 'POST', 1, 'admin', '研发部门', '/tool/gen/createTable', '127.0.0.1', '内网IP', '{\"sql\":\"use `ru-vue`\\n-- 图书表\\nCREATE TABLE `book` (\\n  `book_id`          bigint(20) NOT NULL AUTO_INCREMENT COMMENT \'图书编号\',\\n  `book_name`        varchar(100) NOT NULL COMMENT \'书名\',\\n  `author`           varchar(50)  DEFAULT NULL COMMENT \'作者\',\\n  `isbn`             varchar(20)  DEFAULT NULL COMMENT \'ISBN\',\\n  `publish_date`     date         DEFAULT NULL COMMENT \'出版日期\',\\n  `price`            decimal(10,2) DEFAULT NULL COMMENT \'价格\',\\n  `stock`            int(11) DEFAULT \'0\' COMMENT \'库存\',\\n  `status`           char(1) DEFAULT \'0\' COMMENT \'状态（0正常 1停用）\',\\n  `create_by`        varchar(64)  DEFAULT NULL COMMENT \'创建者\',\\n  `create_time`      datetime     DEFAULT NULL COMMENT \'创建时间\',\\n  `update_by`        varchar(64)  DEFAULT NULL COMMENT \'更新者\',\\n  `update_time`      datetime     DEFAULT NULL COMMENT \'更新时间\',\\n  `remark`           varchar(500) DEFAULT NULL COMMENT \'备注\',\\n  PRIMARY KEY (`book_id`)\\n) ENGINE=InnoDB AUTO_INCREMENT=1 DEFAULT CHARSET=utf8mb4 COMMENT=\'图书表\';\\n\\n-- 初始化两条数据\\nINSERT INTO book VALUES (1,\'SpringBoot实战\',\'Craig Walls\',\'9787115470209\',\'2018-01-01\',89.00,100,\'0\',\'admin\',now(),\'admin\',now(),\'\');\\nINSERT INTO book VALUES (2,\'Vue.js入门\',\'尤雨溪\',\'9787121353049\',\'2019-05-01\',79.00,50,\'0\',\'admin\',now(),\'admin\',now(),\'\');\"}', '{\"msg\":\"创建表结构异常\",\"code\":500}', 0, NULL, '2025-11-18 18:12:48', 2);
INSERT INTO `sys_oper_log` VALUES (102, '代码生成', 6, 'com.ruoyi.generator.controller.GenController.importTableSave()', 'POST', 1, 'admin', '研发部门', '/tool/gen/importTable', '127.0.0.1', '内网IP', '{\"tables\":\"book\"}', '{\"msg\":\"操作成功\",\"code\":200}', 0, NULL, '2025-11-18 18:13:39', 84);
